import React, { useMemo, useRef, useState } from 'react';

import { CIS_COUNTRIES, Countries, PhoneInputProps } from './PhoneInput.types';

import './PhoneInput.scss';
import '../TextField/TextField.scss';

import { MaskField } from ':components/MaskField';
import { classNames } from ':helpers/classnames';
import { CountrySelect } from './CountrySelect';
import { CountriesData } from './CountrySelect/Countries.const';

function getCountriesData(keys) {
	const keySet = new Set(keys);
	return Object.fromEntries(Object.entries(CountriesData).filter(([key]) => keySet.has(key)));
}

export const PhoneInput: React.FC<PhoneInputProps> = ({
	className,
	size = 'medium',
	options = CIS_COUNTRIES,
	defaultCountry = Countries.RU,
	helperPosition = 'absolute',
	value,
	onChange,
	disabled,
	error,
	helperText,
	label = 'Телефон',
	dataTestId = 'PhoneInput',
	disableMaxLength,
	maxLength,
	...rest
}) => {
	const phoneInputRef = useRef<HTMLDivElement | null>(null);
	const contentRef = useRef<HTMLDivElement>(null);
	const [isSelectOpen, setIsSelectOpen] = useState(false);

	const [selectedCountry, setSelectedCountry] = useState(CountriesData[defaultCountry]);

	const [isFocused, setIsFocused] = useState(false);
	const optionsData = useMemo(() => getCountriesData(options), [options]);

	const showBlock = helperPosition === 'block';
	const showAbs = helperText && helperPosition === 'absolute';

	const clearValue = () => String(value).replace(selectedCountry.phoneCode, '');
	return (
		<div
			ref={phoneInputRef}
			data-testid={dataTestId}
			{...rest}
			className={classNames(
				'dsb_phoneinput',
				`dsb_phoneinput-${size}`,
				disabled && 'dsb_phoneinput-disabled',
				(isFocused || isSelectOpen) && !disabled && 'dsb_phoneinput-focus',
				clearValue() && 'dsb_phoneinput-filled',
				error && 'dsb_phoneinput-error',
				className,
			)}
		>
			{showAbs && <sup className="dsb_phoneinput__helpertext dsb_phoneinput__helpertext--absolute">{helperText}</sup>}
			<div ref={contentRef} className="dsb_phoneinput__content">
				<CountrySelect
					targetElement={contentRef}
					isOpen={isSelectOpen}
					handleSetOpen={setIsSelectOpen}
					value={selectedCountry}
					options={optionsData}
					onClick={(event, countryValue) => {
						onChange(event, value.replace(selectedCountry.phoneCode, countryValue.phoneCode));
						setSelectedCountry(countryValue), setIsSelectOpen(false);
					}}
				/>

				<MaskField
					onFocus={() => setIsFocused(true)}
					onBlur={() => setIsFocused(false)}
					className="dsb_phoneinput__maskfield"
					size={size}
					label={label}
					value={clearValue()}
					onChange={(event, value) => {
						onChange(event, `${selectedCountry.phoneCode}${value}`);
					}}
					maskConfig={{
						mask: `${selectedCountry.phoneCode} (000) 000 00 00`,
						lazy: false,
						placeholderChar: '_',
					}}
					fullWidth
					disabled={disabled}
					disableMaxLength={disableMaxLength}
					maxLength={maxLength}
				/>
			</div>
			{showBlock && (
				<div className="dsb_phoneinput__helpertext-block-wrapper">
					<sup className="dsb_phoneinput__helpertext">{helperText}</sup>
				</div>
			)}
		</div>
	);
};
